fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Long {
    val MOD = 1_000_000_007L
    for (query in queries) {
        val (li, ri, ki, vi) = query
        var idx = li
        while (idx <= ri) {
            nums[idx.toInt()] = (nums[idx.toInt()] * vi) % MOD
            idx += ki
        }
    }
    var result = 0L
    for (num in nums) {
        result = result xor num
    }
    return result
}
